draw(Circle(O, 1/3));
draw((0,1/3)--(2/3,1/3));
draw((1/3,0)--(1/3,2/3));

draw((2/3, 0)--(2/3, 1/3));
draw((1/16,0)--(1/16,1/16)--(0,1/16));

label("$A$",A, SW);
label("$B$",B, down);
